// menu.js - كود واحد كامل
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  const texts = ["مرحباً بكم", "أهلاً وسهلاً", "تفضلوا", "استمتعوا", "أهلاً بكم"];

  // كاردات بأحجام ومواضع عشوائية مختلفة
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 130, top: "5%", left: "2%", rotate: -5, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 100, top: "25%", right: "1%", rotate: 8, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 120, bottom: "15%", left: "1%", rotate: -3, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 90, top: "60%", right: "3%", rotate: 12, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
    { id: 5, name: "قهوة", icon: "☕", color: "#cd6133", size: 110, top: "15%", right: "5%", rotate: -8, image: "https://cdn-icons-png.flaticon.com/512/924/924514.png" },
    { id: 6, name: "عصائر", icon: "🍹", color: "#218c74", size: 95, bottom: "30%", left: "3%", rotate: 6, image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" },
    { id: 7, name: "ساندويش", icon: "🥪", color: "#e67e22", size: 115, top: "75%", right: "4%", rotate: -10, image: "https://cdn-icons-png.flaticon.com/512/1046/1046788.png" },
    { id: 8, name: "سلطة", icon: "🥗", color: "#2ecc71", size: 85, top: "45%", left: "4%", rotate: 4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046792.png" },
    { id: 9, name: "بيتزا", icon: "🍕", color: "#e74c3c", size: 125, bottom: "10%", right: "2%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1046/1046796.png" },
    { id: 10, name: "آيس كريم", icon: "🍦", color: "#9b59b6", size: 80, top: "85%", left: "6%", rotate: 15, image: "https://cdn-icons-png.flaticon.com/512/1046/1046800.png" }
  ];

  // تغيير النص في المنتصف
  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  // حركة الماوس
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 50,
        y: (e.clientY / window.innerHeight - 0.5) * 50
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.12) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* نجوم صغيرة */}
      {[...Array(50)].map((_, i) => (
        <div key={i} style={{
          position: "absolute",
          left: `${Math.random() * 100}%`,
          top: `${Math.random() * 100}%`,
          width: `${Math.random() * 3 + 1}px`,
          height: `${Math.random() * 3 + 1}px`,
          background: "white",
          borderRadius: "50%",
          opacity: Math.random() * 0.5,
          animation: `twinkle ${Math.random() * 3 + 2}s infinite`
        }}></div>
      ))}

      <style>{`
        @keyframes twinkle {
          0%, 100% { opacity: 0.2; }
          50% { opacity: 1; }
        }
        @keyframes float {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          50% { transform: translateY(-10px) rotate(5deg); }
        }
      `}</style>

      {/* الكاردات بشكل عشوائي */}
      {cards.map((card) => (
        <div
          key={card.id}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.7 : -0.5)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.6 : 0.6)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 10,
            cursor: "pointer",
            animation: `float ${Math.random() * 3 + 2}s ease-in-out infinite`,
            animationDelay: `${Math.random() * 2}s`
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}99)`,
            width: `${card.size}px`,
            padding: `${card.size / 8}px ${card.size / 12}px`,
            borderRadius: "30px",
            textAlign: "center",
            boxShadow: "0 20px 40px rgba(0,0,0,0.3)",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255,255,255,0.25)",
            transition: "all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.2) rotate(${card.rotate + 10}deg)`;
            e.currentTarget.style.boxShadow = "0 30px 50px rgba(0,0,0,0.5)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 20px 40px rgba(0,0,0,0.3)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: `${card.size / 2.5}px`, 
                height: `${card.size / 2.5}px`, 
                marginBottom: "8px", 
                filter: "drop-shadow(2px 4px 8px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "8px 0 5px", 
              fontSize: `${card.size / 12}px`, 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: `${card.size / 6}px` }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* النص المتحرك في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.25}px, ${mousePosition.y * 0.25}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.15s ease-out"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.6)",
          backdropFilter: "blur(25px)",
          padding: "50px 80px",
          borderRadius: "60px",
          border: "2px solid rgba(34,197,94,0.5)",
          boxShadow: "0 0 80px rgba(34,197,94,0.2), 0 20px 40px rgba(0,0,0,0.3)"
        }}>
          <h1 style={{
            fontSize: "3.8rem",
            fontWeight: "bold",
            background: "linear-gradient(135deg, #ffffff, #22c55e, #4ade80)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0,
            letterSpacing: "2px"
          }}>
            {texts[textIndex]}
          </h1>
          <p style={{ color: "#ddd", marginTop: "15px", fontSize: "1.2rem" }}>✨ مرحباً بكم في قائمتنا ✨</p>
          <div style={{
            width: "80px",
            height: "3px",
            background: "linear-gradient(90deg, #22c55e, #4ade80, transparent)",
            margin: "20px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      </div>

      {/* نص سفلي */}
      <div style={{
        position: "fixed",
        bottom: "20px",
        left: "0",
        right: "0",
        textAlign: "center",
        color: "rgba(255,255,255,0.3)",
        fontSize: "12px",
        zIndex: 30
      }}>
        ✨ حرك الماوس لتتحرك الكاردات ✨
      </div>
    </div>
  );
}
